/* BTSidebar layout — Figma 2346-3623.
   Item-level styles live in internal/BTSidebarItem.css.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

/* ── Root ──────────────────────────────────────────────────────────── */

.bt-sidebar {
  display: flex;
  flex-direction: column;
  /* 16px gap between every top-level section (header, search-row, nav, footer) */
  gap: var(--space-lg);
  /* Fixed open width — min/max enforce it even inside flex parents */
  width: 258px;
  min-width: 258px;
  max-width: 258px;
  height: 100%;
  background: var(--bg-primary);
  border-inline-end: 1px solid var(--border-primary);
  /* Padding: 16px all sides in open state.
     Sections no longer carry their own horizontal padding — aside owns it. */
  padding: var(--space-lg);
  transition: width 0.3s ease, min-width 0.3s ease, max-width 0.3s ease,
              padding 0.3s ease;
  overflow: hidden;
  flex-shrink: 0;
}

.bt-sidebar--collapsed {
  width: 64px;
  min-width: 64px;
  max-width: 64px;
  /* Collapsed: no horizontal padding — items center themselves */
  padding: var(--space-lg) 0;
}

/* ── Header ─────────────────────────────────────────────────────────── */

.bt-sidebar__header {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
  /* margin: sidebar gap: 16px handles section spacing */
}

.bt-sidebar--collapsed .bt-sidebar__header {
  justify-content: center;
  gap: 0;
}

.bt-sidebar__logo {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  object-fit: cover;
  flex-shrink: 0;
}

.bt-sidebar__header-text {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  flex: 1;
  min-width: 0;
  overflow: hidden;
  max-width: 180px;
  transition: opacity 0.2s ease, max-width 0.3s ease, flex 0.3s ease;
}

.bt-sidebar--collapsed .bt-sidebar__header-text {
  opacity: 0;
  max-width: 0;
  flex: 0;
  pointer-events: none;
}

.bt-sidebar__header-title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-sidebar__header-desc {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* ── Search + toggle row ────────────────────────────────────────────── */

.bt-sidebar__search-row {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: var(--space-sm);
  flex-shrink: 0;
  /* padding-bottom: sidebar gap: 16px handles section spacing */
}

.bt-sidebar--collapsed .bt-sidebar__search-row {
  justify-content: center;
}

/* Wrapper gives BTInputSearch flex-1 behaviour */
.bt-sidebar__search-wrapper {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  transition: opacity 0.2s ease, flex 0.3s ease;
}

/* Toggle icon — 16×16 Figma icon inside BTButton icon-only small. */
.bt-sidebar__toggle-icon {
  width: 16px;
  height: 16px;
  display: block;
  pointer-events: none;
  flex-shrink: 0;
}

/* RTL: flip the directional arrow horizontally so |← becomes →| and →| becomes |←,
   matching the sidebar's mirrored position on the right edge. */
[dir="rtl"] .bt-sidebar__toggle-icon {
  transform: scaleX(-1);
}

/* ── Navigation container ────────────────────────────────────────────── */

.bt-sidebar__nav {
  flex: 1;
  overflow-y: auto;
  /* Bleed nav to aside border edges so scrollbar sits flush at aside border,
     not inside the 16px padding area. 16px horizontal padding restores the
     aside content boundary — item backgrounds align with the search input. */
  margin: 0 -16px;
  padding: 0 var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.bt-sidebar__nav--scroll {
  /* Thin scrollbar indicator when hasScroll=true */
}

.bt-sidebar--collapsed .bt-sidebar__nav {
  /* Collapsed aside has padding: 16px 0 (no horizontal) — no negative margin needed */
  margin: 0;
  padding: 0;
  align-items: center;
}

/* Thin scrollbar */
.bt-sidebar__nav::-webkit-scrollbar {
  width: 4px;
}

.bt-sidebar__nav::-webkit-scrollbar-thumb {
  background: var(--border-primary);
  border-radius: var(--radius-xs);
}

.bt-sidebar__nav::-webkit-scrollbar-track {
  background: transparent;
}

/* ── Item group wrapper (holds item row + children) ──────────────────── */

.bt-sidebar__item-group {
  display: flex;
  flex-direction: column;
}

/* BTTooltip wrapper inside sidebar: stretch to fill nav width (overrides inline-flex shrink-wrap) */
.bt-sidebar .bt-tooltip {
  display: flex;
  align-self: stretch;
  min-width: 0;
}

/* Open sidebar: sidebar item must fill the full width of its BTTooltip trigger wrapper.
   Without this, .bt-sidebar-item (display:flex) only takes content width inside
   the flex-row .bt-tooltip container, so hover/active backgrounds don't span the row. */
.bt-sidebar:not(.bt-sidebar--collapsed) .bt-tooltip > .bt-sidebar-item {
  flex: 1;
  min-width: 0;
}

/* ── Divider ─────────────────────────────────────────────────────────── */

.bt-sidebar__divider {
  height: 1px;
  background: var(--border-primary);
}

/* Collapsed: show a short centred line (32 px) instead of the full-width rule */
.bt-sidebar--collapsed .bt-sidebar__divider {
  width: 32px;
  align-self: center;
}

/* ── Sub Title (section label) ───────────────────────────────────────── */

.bt-sidebar__subtitle {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding-block: 8px;
  padding-inline-end: 4px;
  padding-inline-start: 0; /* nav already gives 16px from border; no extra start indent needed */
  white-space: nowrap;
  overflow: hidden;
  max-height: 36px;
  transition: opacity 0.25s ease, max-height 0.3s ease, padding-block 0.3s ease;
}

.bt-sidebar--collapsed .bt-sidebar__subtitle {
  opacity: 0;
  max-height: 0;
  padding-block: 0;
  pointer-events: none;
}

/* ── Children expand/collapse container ──────────────────────────────── */

.bt-sidebar__children {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  max-height: 0;
  gap: var(--space-lg);
  padding-top: 0;
  transition: max-height 0.25s ease, padding-top 0.25s ease;
}

.bt-sidebar__item-group--expanded > .bt-sidebar__children {
  max-height: 2000px;
  padding-top: var(--space-lg);
}

/* Collapsed: force all children shut */
.bt-sidebar--collapsed .bt-sidebar__children {
  max-height: 0;
  padding-top: 0;
}

/* ── Footer ──────────────────────────────────────────────────────────── */

.bt-sidebar__footer {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
  /* padding-top: sidebar gap: 16px handles section spacing */
}

.bt-sidebar--collapsed .bt-sidebar__footer {
  justify-content: center;
  gap: 0;
}

/* BTAvatar (size="sm") handles its own 32×32 circle — no extra styles needed here. */

.bt-sidebar__footer-text {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  flex: 1;
  overflow: hidden;
  max-width: 160px;
  transition: opacity 0.2s ease, max-width 0.3s ease;
}

.bt-sidebar--collapsed .bt-sidebar__footer-text {
  opacity: 0;
  max-width: 0;
  pointer-events: none;
}

.bt-sidebar__footer-name {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-sidebar__footer-email {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

import type { BTAvatarItem } from '../avatar/BTAvatar.types';

export type { BTAvatarItem };

export type BTSidebarItemType = 'Main' | 'Submenu' | 'Sub Submenu' | 'Sub Title' | 'Divider';

export interface BTSidebarNavItem {
  /** Unique identifier for the item. */
  id: string;
  /** Layout / visual type. */
  type: BTSidebarItemType;
  /** Display label — unused for Divider. */
  label?: string;
  /**
   * Icon for Main items — any image/SVG URL (data URI or path).
   * Rendered via CSS mask-image so state colors (active/disabled) work automatically.
   * Pass a data-URI SVG for full color theming support.
   * For fully custom icon rendering, omit this and use the BTSidebarItem #icon slot directly.
   */
  icon?: string;
  /** Whether this item is the currently selected / active page. */
  active?: boolean;
  /** Non-interactive item (visually dimmed, no click). */
  disabled?: boolean;
  /** Child items: Main → Submenu → Sub Submenu. */
  children?: BTSidebarNavItem[];
}

/**
 * Sidebar header data — title and description only.
 * The logo is rendered via the `#logo` named slot on `<BTSidebar>` (any element accepted):
 *
 * ```vue
 * <BTSidebar :header="{ title: 'App', description: 'Workspace' }">
 *   <template #logo>
 *     <img src="/logo.svg" class="bt-sidebar__logo" alt="App" />
 *   </template>
 * </BTSidebar>
 * ```
 */
export interface BTSidebarHeader {
  /** Application or workspace title (bold 14 px). */
  title?: string;
  /** Subtitle / description line (12 px text-secondary). */
  description?: string;
}

export interface BTSidebarFooterUser {
  /**
   * Avatar payload passed directly to BTAvatar.
   * Contains: `name` (for initials fallback), optional `imageUrl`, optional `color`.
   * When omitted, BTAvatar renders the empty/person-icon state.
   */
  item?: BTAvatarItem;
  /** User email address (12 px text-secondary). */
  email?: string;
}

export interface BTSidebarProps {
  /** Expanded (258 px) when true, collapsed (64 px) when false. */
  open?: boolean;
  /** Show scrollbar in the nav area. */
  hasScroll?: boolean;
  /** Header logo + title + description. */
  header?: BTSidebarHeader;
  /** Navigation item tree (Main → Submenu → Sub Submenu). */
  items?: BTSidebarNavItem[];
  /** Controlled search input value. */
  searchValue?: string;
  /**
   * Item IDs that should be expanded on first render.
   * Useful for demos and deep-link navigation.
   */
  initialExpandedIds?: string[];
  // footer content is passed via the #footer named slot
}

export { default as BTSidebar } from './BTSidebar.vue';
export { default as BTSidebarItem } from './internal/BTSidebarItem.vue';
export type {
  BTSidebarProps,
  BTSidebarNavItem,
  BTSidebarItemType,
  BTSidebarHeader,
  BTSidebarFooterUser,
} from './BTSidebar.types';

import type { InjectionKey, ComputedRef } from 'vue';

/**
 * Context provided by BTSidebar to all descendant BTSidebarItem components.
 * Allows items to reactively respond to the sidebar's open/collapsed state
 * without needing an explicit prop at every level.
 */
export interface BTSidebarContext {
  /** Whether the sidebar is in expanded (true) or icon-rail (false) state. */
  open: ComputedRef<boolean>;
}

export const SIDEBAR_INJECTION_KEY: InjectionKey<BTSidebarContext> =
  Symbol('BTSidebarContext');

/* BTSidebarItem — Figma 159-1729.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

/* ── Base row ───────────────────────────────────────────────────────── */

.bt-sidebar-item {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  border-radius: var(--radius-sm);
  cursor: pointer;
  user-select: none;
  transition: background 0.15s;
  position: relative;
}

/* ── Type-specific padding ──────────────────────────────────────────── */

/* Main: p-8px (all sides equal) */
.bt-sidebar-item--main {
  padding: var(--space-sm);
}

/* Submenu: indented left side */
.bt-sidebar-item--submenu {
  padding: var(--space-sm);
}

/* Sub Submenu: deeper indent — fixed, no shift on hover/disabled */
.bt-sidebar-item--sub-submenu {
  padding: var(--space-sm) var(--space-sm) var(--space-sm) var(--space-xl);
}

/* ── Interactive states ─────────────────────────────────────────────── */

.bt-sidebar-item:hover:not(.bt-sidebar-item--active):not(.bt-sidebar-item--disabled) {
  background: var(--bg-secondary);
}

.bt-sidebar-item--active {
  background: var(--color-brand-primary-subtle);
}

.bt-sidebar-item--disabled {
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Collapsed sidebar: 32×32 icon-only pill, hide submenu rows ─────── */

.bt-sidebar-item--collapsed.bt-sidebar-item--main {
  justify-content: center;
  align-items: center;
  width: 32px;
  height: 32px;
  min-height: 32px;
  padding: var(--space-sm);
  gap: 0; /* suppress gap so label (0px) doesn't push icon off-center */
  align-self: center; /* center within the flex-column sidebar nav */
}

.bt-sidebar-item--collapsed.bt-sidebar-item--submenu,
.bt-sidebar-item--collapsed.bt-sidebar-item--sub-submenu {
  display: none;
}

/* ── Icon (Main items) — rendered as CSS mask so color is fully state-driven ── */

.bt-sidebar-item__icon {
  /* Mask-based icon: background-color = the visible icon color.
     The SVG data-URI is used as a shape mask — its own stroke/fill colors are ignored.
     Only the alpha channel of the SVG determines which pixels are colored. */
  display: block;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  background-color: var(--text-primary);   /* default: dark text color */
  -webkit-mask-size: contain;
  mask-size: contain;
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-position: center;
  mask-position: center;
  transition: background-color 0.15s;
}

/* Active → brand primary */
.bt-sidebar-item--active .bt-sidebar-item__icon {
  background-color: var(--color-brand-primary);
}

/* Hover (non-active, non-disabled) → brand primary */
.bt-sidebar-item:hover:not(.bt-sidebar-item--active):not(.bt-sidebar-item--disabled)
  .bt-sidebar-item__icon {
  background-color: var(--color-brand-primary);
}

/* Disabled → disabled token */
.bt-sidebar-item--disabled .bt-sidebar-item__icon {
  background-color: var(--text-disabled);
}

/* ── Dot indicator (Submenu / Sub Submenu) ──────────────────────────── */

.bt-sidebar-item__dot {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.bt-sidebar-item__dot::after {
  content: '';
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-secondary);
  transition: background 0.15s;
}

/* Active dot */
.bt-sidebar-item--active .bt-sidebar-item__dot::after {
  background: var(--color-brand-primary);
}

/* Hover dot */
.bt-sidebar-item:hover:not(.bt-sidebar-item--disabled) .bt-sidebar-item__dot::after {
  background: var(--color-brand-primary);
}

/* Disabled dot */
.bt-sidebar-item--disabled .bt-sidebar-item__dot::after {
  background: var(--text-disabled);
}

/* ── Label ──────────────────────────────────────────────────────────── */

.bt-sidebar-item__label {
  flex: 1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  transition: opacity 0.2s ease, max-width 0.3s ease, color 0.15s;
}

/* Submenu / Sub Submenu: smaller text */
.bt-sidebar-item--submenu .bt-sidebar-item__label,
.bt-sidebar-item--sub-submenu .bt-sidebar-item__label {
  font-size: var(--typography-font-size-xs);
  line-height: var(--typography-line-height-xs);
}

/* Active label: brand primary, bolder weight */
.bt-sidebar-item--active .bt-sidebar-item__label {
  color: var(--color-brand-primary);
  font-weight: 700;
}

/* Active Submenu / Sub Submenu: 600 weight */
.bt-sidebar-item--active.bt-sidebar-item--submenu .bt-sidebar-item__label,
.bt-sidebar-item--active.bt-sidebar-item--sub-submenu .bt-sidebar-item__label {
  font-weight: 600;
}

/* Disabled label */
.bt-sidebar-item--disabled .bt-sidebar-item__label {
  color: var(--text-disabled);
}

/* Hover label (non-active, non-disabled) */
.bt-sidebar-item:hover:not(.bt-sidebar-item--active):not(.bt-sidebar-item--disabled)
  .bt-sidebar-item__label {
  color: var(--color-brand-primary);
}

/* Collapsed: hide labels */
.bt-sidebar-item--collapsed .bt-sidebar-item__label {
  opacity: 0;
  max-width: 0;
  pointer-events: none;
  overflow: hidden;
}

/* ── Chevron ────────────────────────────────────────────────────────── */

.bt-sidebar-item__chevron {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  color: var(--text-secondary);
  transition: transform 0.2s ease, opacity 0.2s ease;
}

/* Expanded: chevron rotates 90° */
.bt-sidebar-item--expanded .bt-sidebar-item__chevron {
  transform: rotate(90deg);
}

/* Collapsed: hide chevron */
.bt-sidebar-item--collapsed .bt-sidebar-item__chevron {
  opacity: 0;
  max-width: 0;
  overflow: hidden;
}
